import { useEffect, useRef, useState } from "react";
import { lerp, clamp, ease } from "./helpers";

const DATA = [
  2.52, 2.61, 2.75, 2.88, 2.95, 3.10, 3.28, 3.45, 3.62, 3.85,
  4.10, 4.38, 4.70, 5.05, 5.45, 5.90, 6.40, 6.95, 7.55, 8.20,
  8.90, 9.30, 9.62, 9.85, 10.0
];

export default function FraudSection() {
  const [progress, setProgress] = useState(0);
  const sectionRef = useRef(null);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current; if (!el) return;
      const rect = el.getBoundingClientRect();
      const p = clamp(-rect.top / (el.offsetHeight - window.innerHeight), 0, 1);
      setProgress(p);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const titleP  = ease(clamp(progress / 0.25, 0, 1));
  const chartP  = ease(clamp((progress - 0.15) / 0.40, 0, 1));
  const bottomP = ease(clamp((progress - 0.50) / 0.25, 0, 1));
  const footerP = ease(clamp((progress - 0.70) / 0.20, 0, 1));

  const W = 900, H = 240;
  const pad = { top: 20, right: 20, bottom: 30, left: 10 };
  const innerW = W - pad.left - pad.right;
  const innerH = H - pad.top - pad.bottom;
  const minV = Math.min(...DATA), maxV = Math.max(...DATA);
  const pts = DATA.map((v, i) => ({
    x: pad.left + (i / (DATA.length - 1)) * innerW,
    y: pad.top + (1 - (v - minV) / (maxV - minV)) * innerH,
  }));

  const visibleCount = Math.max(2, Math.round(chartP * DATA.length));
  const visiblePts = pts.slice(0, visibleCount);
  const polyline = visiblePts.map(p => `${p.x},${p.y}`).join(" ");
  const area = visiblePts.length > 1
    ? `M${visiblePts[0].x},${pad.top + innerH} ` +
      visiblePts.map(p => `L${p.x},${p.y}`).join(" ") +
      ` L${visiblePts[visiblePts.length - 1].x},${pad.top + innerH} Z`
    : "";

  const barBaseY = pad.top + innerH;
  const barWidth = (innerW / DATA.length) * 0.52;

  // Dot indices — sparse, every 3rd
  const dotIndices = DATA.map((_, i) => i).filter(i => i % 3 === 0);

  return (
    <div ref={sectionRef} style={{ height: "280vh", position: "relative" }}>
      <div style={{
        position: "sticky", top: 0, height: "100vh", overflow: "hidden",
        background: "#0d0d0d",
        display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center",
        padding: "60px 48px 36px",
      }}>

        {/* Title */}
        <h2 style={{
          fontFamily: "'Inter','Helvetica Neue',sans-serif",
          fontSize: "clamp(52px,7.8vw,120px)",
          fontWeight: 800, color: "white", margin: "0 0 24px",
          textAlign: "center", lineHeight: 1.05,
          opacity: titleP, transform: `translateY(${lerp(30, 0, titleP)}px)`,
          maxWidth: 1200, whiteSpace: "nowrap",
        }}>
          The Fraud Behind the Workforce
        </h2>

        {/* Subtitle */}
        <p style={{
          color: "rgba(255,255,255,0.85)", fontSize: "clamp(14px,1.2vw,20px)",
          fontWeight: 600, margin: "0 0 32px", textAlign: "center",
          opacity: titleP, transform: `translateY(${lerp(20, 0, titleP)}px)`,
        }}>
          India's gig workforce has grown from
        </p>

        {/* Chart */}
        <div style={{
          width: "100%", maxWidth: 1000,
          opacity: chartP, transform: `translateY(${lerp(20, 0, chartP)}px)`,
        }}>
          <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", overflow: "visible" }}>
            <defs>
              <linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor="rgba(255,255,255,0.18)" />
                <stop offset="100%" stopColor="rgba(255,255,255,0)" />
              </linearGradient>
              {/* Glow filter for line */}
              <filter id="glow">
                <feGaussianBlur stdDeviation="2.5" result="blur" />
                <feMerge>
                  <feMergeNode in="blur" />
                  <feMergeNode in="SourceGraphic" />
                </feMerge>
              </filter>
            </defs>

            {/* Vertical bars */}
            {pts.slice(0, visibleCount).map((p, i) => (
              <rect
                key={i}
                x={p.x - barWidth / 2}
                y={p.y}
                width={barWidth}
                height={barBaseY - p.y}
                fill="rgba(255,255,255,0.09)"
                rx={1}
              />
            ))}

            {/* Area fill */}
            {area && <path d={area} fill="url(#areaGrad)" />}

            {/* Line with glow */}
            {visiblePts.length > 1 && (
              <polyline
                points={polyline}
                fill="none"
                stroke="white"
                strokeWidth="2.5"
                strokeLinejoin="round"
                strokeLinecap="round"
                filter="url(#glow)"
              />
            )}

            {/* Dots on sparse indices */}
            {dotIndices.filter(i => i < visibleCount).map(i => (
              <circle key={i} cx={pts[i].x} cy={pts[i].y} r={4.5} fill="#e53e3e" />
            ))}

            {/* Last dot — larger with ring */}
            {visiblePts.length > 1 && (() => {
              const last = visiblePts[visiblePts.length - 1];
              return (
                <g>
                  <circle cx={last.x} cy={last.y} r={10} fill="rgba(229,62,62,0.2)" />
                  <circle cx={last.x} cy={last.y} r={6} fill="#e53e3e" />
                </g>
              );
            })()}

            {/* Baseline */}
            <line
              x1={pad.left} y1={barBaseY}
              x2={pad.left + innerW} y2={barBaseY}
              stroke="rgba(255,255,255,0.18)" strokeWidth="1"
              strokeDasharray="5 5"
            />
          </svg>

          {/* Bottom labels row */}
          <div style={{
            display: "flex", alignItems: "flex-start", justifyContent: "space-between",
            marginTop: 12,
            opacity: bottomP, transform: `translateY(${lerp(16, 0, bottomP)}px)`,
          }}>
            <div>
              <div style={{
                color: "#e53e3e", fontSize: "clamp(20px,2.8vw,36px)", fontWeight: 800,
                fontFamily: "'Inter',sans-serif", lineHeight: 1.15,
              }}>25.2 lakh</div>
              <div style={{ color: "rgba(255,255,255,0.55)", fontSize: 13, marginTop: 2 }}>workers in 2011</div>
            </div>

            {/* Arrow connector */}
            <div style={{
              display: "flex", alignItems: "center", gap: 10,
              flex: 1, margin: "10px 20px 0",
            }}>
              <div style={{ flex: 1, height: 1.5, background: "#e53e3e" }} />
              <span style={{ color: "white", fontSize: 12, fontWeight: 700, letterSpacing: 3 }}>TO</span>
              <div style={{ flex: 1, height: 1.5, background: "#e53e3e", position: "relative" }}>
                <div style={{
                  position: "absolute", right: -7, top: "50%",
                  transform: "translateY(-50%)",
                  width: 0, height: 0,
                  borderTop: "5px solid transparent",
                  borderBottom: "5px solid transparent",
